changeSet.sql:
DECLARE @authorId BIGINT;

SELECT TOP 1 @authorId = ur.user_id
FROM user_role ur
JOIN role r ON ur.role_id = r.id
WHERE r.name = 'moderator';

INSERT INTO course (author_id, title, description, published_at)
VALUES
(@authorId, 'course_1', 'course_description_1.', GETDATE()),
(@authorId, 'course_2', 'course_description_2.', GETDATE()),
(@authorId, 'course_3', 'course_description_3', NULL);
